/// <summary>
/// This class is an extension of form InventJournalName, dataSource InventJournalName and field ETGManualAdditionorDeletion
/// </summary>
[ExtensionOf(formDataFieldStr(InventJournalName, InventJournalName, ETGManualAdditionorDeletion))]
internal final class ETGInventJournalName_Extension
{
}

Method.Source:
/// <summary>
/// Validating this field when both journal names are same.
/// </summary>
/// <returns>Boolean</returns>
public boolean  validate()
{
   boolean ret = next validate();

    if(SalesParameters::find().ETGEnableCylinderTracking)
    {
        FormDataObject    formDataObject    = any2Object(this) as FormDataObject;
        FormDataSource    formDataSource    = formDataObject.datasource();
        InventJournalName inventJournalName = formDataSource.cursor();
        str journalName = InventParameters::find().ETGJournalName;

        if(inventJournalName.ETGManualAdditionorDeletion == NoYes::Yes 
            && inventJournalName.JournalNameId == journalName
            && inventJournalName.JournalType == InventJournalType::LossProfit)
        {
            throw Error("@ETG_New:RefillingofCylinderValidation");
        }
    }
    return ret;
}
